const MONSTER_TMP = '/tmp/gnexec-target/release/monster';
const GNOSIS_POLYGLOT_TMP = '/tmp/gnexec-target/release/gnosis-polyglot';

const MONSTER_LOCAL = path.resolve(gnosisDir, 'polyglot/target/release/monster');
const GNEXEC_LOCAL = path.resolve(gnosisDir, 'polyglot/target/release/gnexec');
const GNEXEC = existsSync(MONSTER_TMP)
  ? MONSTER_TMP
  : existsSync(MONSTER_LOCAL)
    ? MONSTER_LOCAL
    : existsSync(GNEXEC_TMP)
      ? GNEXEC_TMP
      : GNEXEC_LOCAL;
const MONSTER_RUNTIME_NAME = path.basename(GNEXEC) === 'monster' ? 'monster' : 'gnexec';
const GNOSIS_POLYGLOT = existsSync(GNOSIS_POLYGLOT_TMP)
  ? GNOSIS_POLYGLOT_TMP
  : path.resolve(gnosisDir, 'polyglot/target/release/gnosis-polyglot');
const POLYGLOT_LIB = path.resolve(
  gnosisDir,
  'polyglot/target/release/libgnosis_polyglot.rlib'
);
const BECKY = path.resolve(gnosisDir, 'polyglot/target/release/becky');
const INVOKE_APP = path.resolve(__dirname, 'invoke-app.mjs');
const RESULTS_JSON = '/tmp/gnexec-bench-results.json';

const ITERATIONS = 5; // 1 warm + 4 measured
const TIMEOUT_MS = 30_000;

/**
 * Per-language wall-time budgets (median, ms). Run fails loudly if a
 * language median crosses this ceiling ‚Äî wall-time guardrail, not exit
 * code. Only applied to gnexec-runtime `pass`-kind cases (extractor IR
 * cases are excluded ‚Äî they run a different binary).
 *
 * Note: today's go/rust/java runtime medians are computed from a single
 * `<lang>-echo` case (kind=expected-unsupported, exits fast). On a noisy
 * laptop the single-sample median can spike past 25 ms purely from
 * scheduler noise. Once gnexec consumes structured IR and these cases
 * become real `pass` cases, samples stabilize. Until then, this budget
 * is a regression *detector* ‚Äî a steady-state >25 ms median is real;
 * one-off spikes are noise. Re-run on failure before treating as a
 * regression.
 */
const LANGUAGE_BUDGET_MS = {
  ts: 25,
  py: 25,
  go: 25,
  rust: 25,
  java: 25,
};

/**
 * Per-case slow-regression ceilings. Map of label ‚Üí ms. Hard-fail if a
 * specific case exceeds this ceiling even when its language median is OK.
 * Currently used to lock in the post-#32 (per-Ctx scratch-arena) target
 * for try/catch ‚Äî current baseline is ~28 ms, target is ~24 ms.
 */
const CASE_SLOW_CEILING_MS = {
  // OPTIMIZATION TARGET (#32 per-Ctx scratch-arena): def-trycatch is the
  // slowest case in the suite (~28 ms steady). Once the per-Ctx scratch
  // arena lands, expect convergence to within 2√ó of baseline (~24 ms).
  // Set ceiling at 50 ms ‚Äî fast-fail on a *worse* regression, not on the
  // current baseline. Tighten to 25 ms after #32 ships.
  'def-trycatch': 50,
};

