/* -------------------------------------------------------------------------- */
/* Runner                                                                     */
/* -------------------------------------------------------------------------- */

function median(xs) {
  if (xs.length === 0) return null;
  const sorted = [...xs].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid];
}

function fileMeta(p) {
  if (!existsSync(p)) return { exists: false };
  const s = statSync(p);
  return {
    exists: true,
    size: s.size,
    mtime: s.mtime.toISOString(),
  };
}

function checkExpected(stdout, expected) {
  const trimmed = stdout.replace(/\n+$/, '');
  if (typeof expected === 'string') {
    return trimmed === expected;
  }
  if (expected instanceof RegExp) {
    return expected.test(trimmed);
  }
  if (typeof expected === 'function') {
    return Boolean(expected(trimmed));
  }
  return false;
}

function runOnce(binary, args, env = process.env) {
  const t0 = performance.now();
  const result = spawnSync(binary, args, {
    encoding: 'utf8',
    timeout: TIMEOUT_MS,
    env,
  });
  const t1 = performance.now();
  return {
    wallMs: t1 - t0,
    exit: result.status,
    signal: result.signal,
    stdout: result.stdout ?? '',
    stderr: result.stderr ?? '',
    timedOut: Boolean(result.error && result.error.code === 'ETIMEDOUT'),
  };
}

function categorize(tc, run) {
  if (run.timedOut) return 'timeout';
  if (run.signal) return `signal-${run.signal}`;

  if (tc.kind === 'expected-throw') {
    if (run.exit !== 1) return `regression-expected-throw-exit-${run.exit}`;
    if (!checkExpected(run.stderr, tc.expect)) {
      return 'regression-expected-throw-msg';
    }
    return 'pass';
  }
  if (tc.kind === 'expected-unsupported') {
    if (run.exit !== (tc.expectedExit ?? 4)) {
      return `regression-unsupported-exit-${run.exit}`;
    }
    return 'pass';
  }
  if (tc.kind === 'extractor-emits-ir') {
    if (run.exit !== 0) return `regression-extractor-exit-${run.exit}`;
    if (!checkExpected(run.stdout, tc.expect)) return 'regression-ir-missing';
    return 'pass';
  }

  if (run.exit !== 0) return `fail-exit-${run.exit}`;
  if (!checkExpected(run.stdout, tc.expect)) return 'wrong-output';
  return 'pass';
}

function runCase(tc, opts = {}) {
  const { useJsBridge = false } = opts;

  if (!existsSync(tc.file)) {
    return {
      ...tc,
      status: 'file-missing',
      runs: [],
      medianWallMs: null,
      stdout: '',
      stderr: '',
      exit: null,
    };
  }

  let binary;
  let args;
  if (useJsBridge) {
    binary = process.execPath; // node
    // Use tsx loader so .ts source files load directly.
    args = [
      '--import',
      'tsx',
      INVOKE_APP,
      tc.file,
      JSON.stringify(tc.input),
      tc.exportName ?? 'app',
    ];
  } else if (tc.kind === 'extractor-emits-ir') {
    // IR regression net: invoke gnosis-polyglot directly with the
    // case's polyglotArgs, then grep stdout for IR markers.
    if (!existsSync(GNOSIS_POLYGLOT)) {
      return {
        ...tc,
        status: 'binary-missing',
        runs: [],
        medianWallMs: null,
        stdout: '',
        stderr: '',
        exit: null,
      };
    }
    binary = GNOSIS_POLYGLOT;
    args = [tc.file, ...(tc.polyglotArgs ?? [])];
  } else {
    if (!existsSync(GNEXEC)) {
      return {
        ...tc,
        status: 'binary-missing',
        runs: [],
        medianWallMs: null,
        stdout: '',
        stderr: '',
        exit: null,
      };
    }
    binary = GNEXEC;
    args = ['--input-json', JSON.stringify(tc.input ?? {})];
    if (tc.exportName) args.push('--export', tc.exportName);
    args.push(tc.file);
  }

  const env = { ...process.env };
  if (useJsBridge) env.GNODE_NO_GNEXEC = '1';

  const runs = [];
  for (let i = 0; i < ITERATIONS; i += 1) {
    runs.push(runOnce(binary, args, env));
  }
  // Median of measured runs (drop the first as warmup).
  const measured = runs.slice(1);
  const medianWallMs = median(measured.map((r) => r.wallMs));

  const last = runs[runs.length - 1];
  const status = useJsBridge
    ? // For JS bridge we just want a coarse pass/fail.
      last.exit === 0 && checkExpected(last.stdout, tc.expect)
      ? 'pass'
      : `fail-exit-${last.exit}`
    : categorize(tc, last);

  return {
    label: tc.label,
    file: tc.file,
    lang: tc.lang,
    kind: tc.kind ?? 'pass',
    exportName: tc.exportName ?? 'app',
    status,
    medianWallMs,
    walls: measured.map((r) => r.wallMs),
    exit: last.exit,
    stdout: last.stdout.slice(0, 400),
    stderr: last.stderr.slice(0, 400),
  };
}

/* -------------------------------------------------------------------------- */
/* Markdown summary                                                           */
/* -------------------------------------------------------------------------- */

function fmtMs(ms) {
  if (ms == null) return '‚Äî';
  if (ms < 10) return `${ms.toFixed(2)} ms`;
  if (ms < 1000) return `${ms.toFixed(1)} ms`;
  return `${(ms / 1000).toFixed(2)} s`;
}

function renderMarkdown(report) {
  const lines = [];
  lines.push(`# ${MONSTER_RUNTIME_NAME} cross-language benchmark`);
  lines.push('');
  lines.push(`- timestamp: \`${report.timestamp}\``);
  lines.push(`- harness git rev: \`${report.gitRev ?? 'null'}\``);
  lines.push(
    `- ${MONSTER_RUNTIME_NAME}: ${
      report.binaries.gnexec.exists
        ? `${report.binaries.gnexec.size} bytes, mtime ${report.binaries.gnexec.mtime}`
        : 'MISSING'
    }`
  );
  lines.push(
    `- gnosis-polyglot lib: ${
      report.binaries.polyglotLib.exists
        ? `${report.binaries.polyglotLib.size} bytes, mtime ${report.binaries.polyglotLib.mtime}`
        : 'MISSING'
    }`
  );
  lines.push(
    `- becky: ${
      report.binaries.becky.exists
        ? `${report.binaries.becky.size} bytes, mtime ${report.binaries.becky.mtime}`
        : 'MISSING'
    }`
  );
  lines.push('');
  lines.push(
    `## Totals: ${report.summary.pass}/${report.summary.knownTotal} known cases pass ¬∑ ${report.summary.skipped} skipped (file/binary missing)`
  );
  lines.push('');

  // Per-language breakdown
  lines.push('## By language');
  lines.push('');
  lines.push(
    '| lang | pass | total | pass-rate | median wall | runtime median | budget |'
  );
  lines.push(
    '|------|------|-------|-----------|-------------|----------------|--------|'
  );
  for (const [lang, agg] of Object.entries(report.byLanguage)) {
    const rate =
      agg.total === 0 ? '‚Äî' : `${((agg.pass / agg.total) * 100).toFixed(0)}%`;
    const budget = report.budgets?.languageBudgetMs?.[lang];
    const budgetCell = budget == null ? '‚Äî' : `< ${budget} ms`;
    lines.push(
      `| ${lang} | ${agg.pass} | ${agg.total} | ${rate} | ${fmtMs(
        agg.medianWallMs
      )} | ${fmtMs(agg.runtimeMedianWallMs)} | ${budgetCell} |`
    );
  }
  lines.push('');

  // Per-case table
  lines.push('## Per-case results');
  lines.push('');
  lines.push('| label | lang | export | status | median | exit |');
  lines.push('|-------|------|--------|--------|--------|------|');
  for (const c of report.cases) {
    lines.push(
      `| ${c.label} | ${c.lang} | ${c.exportName} | ${c.status} | ${fmtMs(c.medianWallMs)} | ${c.exit ?? '‚Äî'} |`
    );
  }
  lines.push('');

  // Slowest 5
  const slowest = [...report.cases]
    .filter((c) => c.medianWallMs != null)
    .sort((a, b) => b.medianWallMs - a.medianWallMs)
    .slice(0, 5);
  lines.push('## Slowest 5');
  lines.push('');
  lines.push('| label | lang | median | status |');
  lines.push('|-------|------|--------|--------|');
  for (const c of slowest) {
    lines.push(
      `| ${c.label} | ${c.lang} | ${fmtMs(c.medianWallMs)} | ${c.status} |`
    );
  }
  lines.push('');

  // JS-bridge floor
  if (report.jsBridge && report.jsBridge.length > 0) {
    lines.push('## JS-bridge floor (GNODE_NO_GNEXEC=1, via tsx)');
    lines.push('');
    lines.push(`| label | ${MONSTER_RUNTIME_NAME} median | js-bridge median | speedup | bridge status |`);
    lines.push('|-------|---------------|------------------|---------|----------------|');
    for (const row of report.jsBridge) {
      const speedup =
        row.gnexecWallMs && row.bridgeWallMs
          ? `${(row.bridgeWallMs / row.gnexecWallMs).toFixed(1)}√ó`
          : '‚Äî';
      lines.push(
        `| ${row.label} | ${fmtMs(row.gnexecWallMs)} | ${fmtMs(
          row.bridgeWallMs
        )} | ${speedup} | ${row.bridgeStatus} |`
      );
    }
    lines.push('');
  }

  // Regressions
  if (report.summary.regressions.length > 0) {
    lines.push('## REGRESSIONS');
    lines.push('');
    for (const r of report.summary.regressions) {
      lines.push(`- **${r.label}** (${r.lang}): ${r.status} ‚Äî exit=${r.exit}`);
      if (r.stderr) lines.push(`  - stderr: \`${r.stderr.split('\n')[0]}\``);
    }
    lines.push('');
  }

  // Wall-time budget violations
  const violations = report.budgets?.violations ?? [];
  if (violations.length > 0) {
    lines.push('## WALL-TIME BUDGET VIOLATIONS');
    lines.push('');
    for (const v of violations) {
      if (v.kind === 'language-budget') {
        lines.push(
          `- lang=\`${v.lang}\` median=${v.observedMs.toFixed(2)} ms > budget=${v.budgetMs} ms`
        );
      } else {
        lines.push(
          `- case=\`${v.label}\` (${v.lang}) median=${v.observedMs.toFixed(2)} ms > ceiling=${v.budgetMs} ms`
        );
      }
    }
    lines.push('');
  }

  return lines.join('\n');
}

/* -------------------------------------------------------------------------- */
/* Main                                                                       */
/* -------------------------------------------------------------------------- */

function getGitRev() {
  const r = spawnSync('git', ['rev-parse', 'HEAD'], {
    cwd: repoRoot,
    encoding: 'utf8',
  });
  if (r.status === 0) return r.stdout.trim();
  return null;
}

function main() {
  const startedAt = new Date().toISOString();

  const binaries = {
    gnexec: fileMeta(GNEXEC),
    polyglotLib: fileMeta(POLYGLOT_LIB),
    becky: fileMeta(BECKY),
  };

  process.stderr.write(`# ${MONSTER_RUNTIME_NAME} cross-language bench\n`);
  process.stderr.write(`# binary: ${GNEXEC}\n`);
  process.stderr.write(
    `#   exists=${binaries.gnexec.exists} size=${binaries.gnexec.size ?? '?'} mtime=${binaries.gnexec.mtime ?? '?'}\n`
  );

  const results = [];
  for (const tc of cases) {
    process.stderr.write(`  ${tc.label.padEnd(28)} `);
    const r = runCase(tc);
    results.push(r);
    process.stderr.write(`${r.status.padEnd(20)} ${fmtMs(r.medianWallMs)}\n`);
  }

  // JS-bridge floor ‚Äî only canonical TS baselines flagged `floor`.
  const jsBridge = [];
  for (const tc of cases) {
    if (!tc.floor) continue;
    process.stderr.write(`  [bridge] ${tc.label.padEnd(20)} `);
    const r = runCase(tc, { useJsBridge: true });
    const gnexecRow = results.find((x) => x.label === tc.label);
    jsBridge.push({
      label: tc.label,
      gnexecWallMs: gnexecRow?.medianWallMs ?? null,
      bridgeWallMs: r.medianWallMs,
      bridgeStatus: r.status,
    });
    process.stderr.write(`${r.status.padEnd(20)} ${fmtMs(r.medianWallMs)}\n`);
  }

  // Aggregations.
  // `medianWallMs` is computed from gnexec-runtime cases only (kind=pass
  // or expected-throw or expected-unsupported). Extractor-emits-ir cases
  // run a different binary on a different code path ‚Äî keep them out of
  // the per-language wall budget so we don't conflate the two axes.
  const byLanguage = {};
  for (const c of results) {
    const lang = c.lang;
    if (!byLanguage[lang]) {
      byLanguage[lang] = {
        pass: 0,
        total: 0,
        walls: [],
        runtimeWalls: [],
      };
    }
    if (c.status === 'file-missing' || c.status === 'binary-missing') continue;
    byLanguage[lang].total += 1;
    if (c.status === 'pass') byLanguage[lang].pass += 1;
    if (c.medianWallMs != null) byLanguage[lang].walls.push(c.medianWallMs);
    // Runtime-only walls: drives the per-language budget gate.
    if (
      c.medianWallMs != null &&
      c.kind !== 'extractor-emits-ir' &&
      c.status === 'pass'
    ) {
      byLanguage[lang].runtimeWalls.push(c.medianWallMs);
    }
  }
  for (const lang of Object.keys(byLanguage)) {
    byLanguage[lang].medianWallMs = median(byLanguage[lang].walls);
    byLanguage[lang].runtimeMedianWallMs = median(
      byLanguage[lang].runtimeWalls
    );
    delete byLanguage[lang].walls;
    delete byLanguage[lang].runtimeWalls;
  }

  const known = results.filter(
    (c) => c.status !== 'file-missing' && c.status !== 'binary-missing'
  );
  const passed = known.filter((c) => c.status === 'pass');
  const skipped = results.filter(
    (c) => c.status === 'file-missing' || c.status === 'binary-missing'
  );
  const regressions = known.filter((c) => c.status !== 'pass');

  const allWalls = passed
    .map((c) => c.medianWallMs)
    .filter((x) => x != null);
  const overallMedianWallMs = median(allWalls);

  // Per-language wall-time budget gate. Hard-fails when any language's
  // gnexec-runtime median crosses LANGUAGE_BUDGET_MS[lang].
  const budgetViolations = [];
  for (const [lang, agg] of Object.entries(byLanguage)) {
    const ceiling = LANGUAGE_BUDGET_MS[lang];
    if (ceiling == null) continue;
    const observed = agg.runtimeMedianWallMs;
    if (observed == null) continue; // No runtime cases (pure IR).
    if (observed > ceiling) {
      budgetViolations.push({
        kind: 'language-budget',
        lang,
        observedMs: observed,
        budgetMs: ceiling,
      });
    }
  }

  // Per-case slow-regression ceilings. Catches cases that blow past their
  // optimization target (e.g. def-trycatch post-#32 must stay under 50 ms).
  for (const c of results) {
    const ceiling = CASE_SLOW_CEILING_MS[c.label];
    if (ceiling == null) continue;
    if (c.medianWallMs == null) continue;
    if (c.status !== 'pass') continue; // Already counted as a regression.
    if (c.medianWallMs > ceiling) {
      budgetViolations.push({
        kind: 'case-ceiling',
        label: c.label,
        lang: c.lang,
        observedMs: c.medianWallMs,
        budgetMs: ceiling,
      });
    }
  }

  const report = {
    timestamp: startedAt,
    gitRev: getGitRev(),
    iterations: ITERATIONS,
    binaries,
    budgets: {
      languageBudgetMs: LANGUAGE_BUDGET_MS,
      caseSlowCeilingMs: CASE_SLOW_CEILING_MS,
      violations: budgetViolations,
    },
    summary: {
      total: results.length,
      knownTotal: known.length,
      pass: passed.length,
      skipped: skipped.length,
      overallMedianWallMs,
      regressions: regressions.map((r) => ({
        label: r.label,
        lang: r.lang,
        status: r.status,
        exit: r.exit,
        stderr: r.stderr,
      })),
    },
    byLanguage,
    cases: results,
    jsBridge,
  };

  writeFileSync(RESULTS_JSON, JSON.stringify(report, null, 2));
  process.stderr.write(`\n# wrote ${RESULTS_JSON}\n\n`);

  // Markdown to stdout.
  process.stdout.write(renderMarkdown(report));
  process.stdout.write('\n');

  if (regressions.length > 0) {
    process.stderr.write(
      `\n# REGRESSIONS (${regressions.length}): ${regressions.map((r) => r.label).join(', ')}\n`
    );
    process.exit(1);
  }
  if (budgetViolations.length > 0) {
    process.stderr.write(`\n# WALL-TIME BUDGET VIOLATIONS\n`);
    for (const v of budgetViolations) {
      if (v.kind === 'language-budget') {
        process.stderr.write(
          `#   lang=${v.lang} median=${v.observedMs.toFixed(2)}ms > budget=${v.budgetMs}ms\n`
        );
      } else {
        process.stderr.write(
          `#   case=${v.label} (${v.lang}) median=${v.observedMs.toFixed(2)}ms > ceiling=${v.budgetMs}ms\n`
        );
      }
    }
    process.exit(2);
  }
  process.exit(0);
}

main();
